contacts.bubbleCss:
/* ==========================================
  1. 文本气泡核心设置 (排除含 svg 和 img 的气泡)
  ========================================== */
/* === 通用基础属性 === */
.message-line .chat-bubble:not(:has(svg)):not(:has(img)) {
   /* 基础排版 */
   position: relative !important;
   width: fit-content;
   max-width: 70vw;
   overflow-wrap: break-word;
   word-break: break-all;
   overflow: visible !important;

   /* 清除原本背景、特效以及毛玻璃模糊效果 */
   background: none !important;
   background-color: transparent !important;
   box-shadow: none !important;
   filter: none !important;
   backdrop-filter: none !important;
   -webkit-backdrop-filter: none !important;
   border-radius: 0 !important;

   /* 必须设置，否则 border-image 不生效 */
   border-style: solid !important;
   border-color: transparent !important;

   /* 核心拉伸参数 (通用) */
   border-image-slice: 45% 40% 50% 40% fill !important;
   border-image-width: 20px !important;
   border-image-outset: 12px !important;
   border-image-repeat: stretch !important;

   /* 字体颜色与阴影清除 */
   color: #000000 !important;
   text-shadow: none !important;
}

/* === 发送方 (右侧) 专属设置 === */
.message-line.sent .chat-bubble.sent:not(:has(svg)):not(:has(img)) {
   /* 设置用户气泡图片 */
   border-image-source: url('https://img.heliar.top/file/1769632807579_7D7C9F8622930268741AD37673EECB15.png') !important;

   /* 内边距：上 右 下 左 */
   padding: 1px 0px 1px 0px !important;

   /* 外边距：控制气泡离右侧头像的距离 */
   margin-right: 10px !important;
}

/* === 接收方 (左侧) 专属设置 === */
.message-line.received .chat-bubble.received:not(:has(svg)):not(:has(img)) {
   /* 设置AI气泡图片 */
   border-image-source: url('https://img.heliar.top/file/1769632811413_2207F8F8FBA3617767BE27F20CD19105.png') !important;

   /* 内边距：上 右 下 左 */
   padding: 1px 0px 1px 0px !important;

   /* 外边距：控制气泡离左侧头像的距离 */
   margin-left: 10px !important;
}

/* ==========================================
  3. 图片/表情包/转账的“免气泡”纯净处理
  ========================================== */
.message-line.sent .chat-bubble.sent:has(svg),
.message-line.sent .chat-bubble.sent:has(img),
.message-line.received .chat-bubble.received:has(svg),
.message-line.received .chat-bubble.received:has(img) {
   /* 彻底透明化并去除毛玻璃 */
   background: transparent !important;
   box-shadow: none !important;
   border: none !important;
   backdrop-filter: none !important;
   -webkit-backdrop-filter: none !important;

   /* 去除多余的边距，让图片原生态贴合 */
   padding: 0 !important;
   margin: 0 !important;
   overflow: visible !important;
}

contacts.offlineCss:
/* ==================== 仿iMessages水色 by Yui，颜色可自改 ==================== */
/* 发送方气泡 */
.message-line.sent .chat-bubble.sent {
 position: relative;
 background: #E3F2FF; /* 清爽的水蓝色 */
 color: #000000;
 padding: 8px 16px;
 border-radius: 20px;
 max-width: 70vw;
 font-family: -apple-system, sans-serif;
 margin-right: 14px;
 line-height: 1.4;
}

/* 发送方小尾巴本体  */
.message-line.sent .chat-bubble.sent::before {
 content: "";
 position: absolute;
 bottom: 0;
 right: -8px;
 width: 20px;
 height: 20px;
 background-color: #E3F2FF;
 border-bottom-left-radius: 16px;
 z-index: -1;

 /* 完美的镂空遮罩 */
 -webkit-mask-image:
   linear-gradient(to right, #000 12px, transparent 12px),
   radial-gradient(circle at 10px 0px, transparent 10px, #000 10.5px);
 -webkit-mask-size: 100% 100%, 10px 10px;
 -webkit-mask-position: 0 0, 12px 10px;
 -webkit-mask-repeat: no-repeat;

 mask-image:
   linear-gradient(to right, #000 12px, transparent 12px),
   radial-gradient(circle at 10px 0px, transparent 10px, #000 10.5px);
 mask-size: 100% 100%, 10px 10px;
 mask-position: 0 0, 12px 10px;
 mask-repeat: no-repeat;
}

/* 接收方气泡 */
.message-line.received .chat-bubble.received {
 position: relative;
 background: #FFFFFF; /* 纯白色 */
 color: #000000;
 padding: 8px 16px;
 border-radius: 20px;
 max-width: 70vw;
 font-family: -apple-system, sans-serif;
 margin-left: 14px;
 line-height: 1.4;
 }

/* 接收方小尾巴本体 */
.message-line.received .chat-bubble.received::before {
 content: "";
 position: absolute;
 bottom: 0;
 left: -8px;
 width: 20px;
 height: 20px;
 background-color: #FFFFFF;
 border-bottom-right-radius: 16px;
 z-index: -1;

 /* 完美的镂空遮罩 */
 -webkit-mask-image:
   linear-gradient(to right, transparent 8px, #000 8px),
   radial-gradient(circle at 0px 0px, transparent 10px, #000 10.5px);
 -webkit-mask-size: 100% 100%, 10px 10px;
 -webkit-mask-position: 0 0, -2px 10px;
 -webkit-mask-repeat: no-repeat;

 mask-image:
   linear-gradient(to right, transparent 8px, #000 8px),
   radial-gradient(circle at 0px 0px, transparent 10px, #000 10.5px);
 mask-size: 100% 100%, 10px 10px;
 mask-position: 0 0, -2px 10px;
 mask-repeat: no-repeat;
}
